local LxBaseState = require("LApp.component.fsm.LxBaseState")
---@class LCityPeopleGoToPointState:LxBaseState 小人状态--建筑寻路完成，去建筑内的点位
local LCityPeopleGoToPointState = classX("LCityPeopleIdleState", LxBaseState)

function LCityPeopleGoToPointState:ctor()

    self._stateType = CityPeopleFsmState.GoToPoint;
    self.moveSpeed = math.random(2.0,2.5);
end
function LCityPeopleGoToPointState:Initialize()
    LxBaseState.Initialize(self)
    ---@type LCityPeopleFsm
    self._fsm = self:GetMachine();
    ---@type LCityPeopleUnit
    self._unit = self._fsm:GetVar("unit");

end
function LCityPeopleGoToPointState:Execute(deltaTime)
    if(self._beginWalk == false)then
        return
    end
    if(self._targetPoint == nil)then
        return
    end
    if (Vector3.Distance(self._unit:GetPosition(), self._targetPoint) <= 0.05) then
        --结束
        self.beginWalk = false;
        self:SetUnitDir()
        self._fsm:ChangeState(CityPeopleFsmState.None)

        return
    end
    self._unit:SetPosition(Vector3.MoveTowards(self._unit:GetPosition(), self._targetPoint, self.moveSpeed * deltaTime));
end

function LCityPeopleGoToPointState:Enter()

    self._unit:SetSpineAlpha(1);
    self._unit:PlayAni("run")
    self._targetPoint = self._fsm:GetVar("targetPoint")
    if(self._targetPoint ~= nil)then
        self._beginWalk = true
    else
        self._beginWalk = false
        self._fsm:ChangeState(CityPeopleFsmState.None)
    end
    self:SetUnitDir()
end
function LCityPeopleGoToPointState:SetUnitDir()
    if(self._targetPoint == nil or self._beginWalk == false)then
        return
    end
    local objPosition = self._unit:GetPosition()
    if(self._targetPoint.x < objPosition.x )then
        self._unit:SetDir(true)
        return
    end
    if(self._targetPoint.x > objPosition.x )then
        self._unit:SetDir(false)
        return
    end
end
function LCityPeopleGoToPointState:Exit()

end
function LCityPeopleGoToPointState:Dispose()
    self._unit = nil
    self._fsm = nil
    LxBaseState.Dispose(self)
end
return LCityPeopleGoToPointState